#!/bin/bash
# encode-all-rknots.sh: Create production rknot packages for all four models
# Combines folded wave stores + saturation bitmasks for deployment

set -e

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
OUTPUT_DIR="${SCRIPT_DIR}/rknots"
FIXTURES_DIR="${SCRIPT_DIR}/fixtures"
BINARY="${SCRIPT_DIR}/target/release/encode-and-upload-rknots"

# Ensure output directory exists
mkdir -p "$OUTPUT_DIR"

echo "=== Gnosis Rknot Encoding Pipeline ==="
echo "Output: $OUTPUT_DIR"
echo ""

# Model configurations: (name, display_name, num_layers)
models=(
  "phi3:Phi3-mini:32"
  "qwen:Qwen2.5-7B:28"
  "gemma4:Gemma4-31B:32"
  "llama:Llama-70B:80"
)

for model_spec in "${models[@]}"; do
  IFS=':' read -r model display_name num_layers <<< "$model_spec"

  echo "[$(date '+%Y-%m-%d %H:%M:%S')] Encoding $display_name..."

  saturation_maps="${FIXTURES_DIR}/saturation-maps-${model}.rs"
  knot_input="${FIXTURES_DIR}/${model}-base.knot"
  knot_output="${OUTPUT_DIR}/${model}-optimized.rknot"

  # Check if input files exist
  if [[ ! -f "$saturation_maps" ]]; then
    echo "  ⚠ Warning: saturation maps not found: $saturation_maps"
    echo "  Using baseline rknot only"
  fi

  if [[ ! -f "$knot_input" ]]; then
    echo "  ⚠ Warning: base rknot not found: $knot_input"
    echo "  Skipping $display_name"
    continue
  fi

  # Encode rknot (embed saturation bitmasks in metadata)
  "$BINARY" \
    --model "$model" \
    --saturation-maps "$saturation_maps" \
    --knot-input "$knot_input" \
    --knot-output "$knot_output" \
    2>&1 | sed 's/^/  /'

  if [[ -f "$knot_output" ]]; then
    size=$(ls -lh "$knot_output" | awk '{print $5}')
    echo "  ✓ Created: $knot_output ($size)"
  else
    echo "  ✗ Failed to create rknot"
    exit 1
  fi
done

echo ""
echo "=== Rknot Encoding Complete ==="
ls -lh "$OUTPUT_DIR"/*.rknot 2>/dev/null || echo "No rknots created"

echo ""
echo "=== Next Steps ==="
echo "1. Verify rknots:"
echo "   file $OUTPUT_DIR/*.rknot"
echo ""
echo "2. Update Moonshine container:"
echo "   docker build -f Dockerfile.moonshine -t gnosis-moonshine:optimized ."
echo ""
echo "3. Deploy to distributed inference:"
echo "   kubectl apply -f k8s/gnosis-moonshine-deployment.yaml"
